@page "/board"
@using sv_79f79cadcfd142a18bb6dcb0ae255502.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats Bar -->
    <div class="row mb-3">
        <div class="col">
            <div class="d-flex gap-3 flex-wrap align-items-center p-2 bg-light rounded">
                <span><strong>Total:</strong> @FilteredTasks.Count</span>
                <span><strong>To Do:</strong> @TodoTasks.Count</span>
                <span><strong>In Progress:</strong> @InProgressTasks.Count</span>
                <span><strong>Done:</strong> @DoneTasks.Count</span>
                <span class="text-danger"><strong>Overdue:</strong> @OverdueCount</span>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="row mb-3">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Search tasks by title..."
                   @bind="_searchText" @bind:event="oninput" />
        </div>
    </div>

    <!-- Kanban Columns -->
    <div class="row">
        @RenderColumn("To Do", TodoTasks, null, "In Progress")
        @RenderColumn("In Progress", InProgressTasks, "To Do", "Done")
        @RenderColumn("Done", DoneTasks, "In Progress", null)
    </div>
}

@code {
    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    private Dictionary<string, bool> _showForm = new()
    {
        ["To Do"] = false,
        ["In Progress"] = false,
        ["Done"] = false
    };

    private Dictionary<string, FormModel> _formModels = new()
    {
        ["To Do"] = new(),
        ["In Progress"] = new(),
        ["Done"] = new()
    };

    private List<TaskItem> FilteredTasks => string.IsNullOrWhiteSpace(_searchText)
        ? _allTasks
        : _allTasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TodoTasks => FilteredTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => FilteredTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => FilteredTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueCount => FilteredTasks.Count(t => t.DueDate < DateTime.Today);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = _allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                _allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task SaveTask(string status)
    {
        var model = _formModels[status];
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            _allTasks.Add(newTask);
            _formModels[status] = new();
            _showForm[status] = false;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }

    private void CancelForm(string status)
    {
        _formModels[status] = new();
        _showForm[status] = false;
    }

    private string GetPriorityClass(string priority) => priority switch
    {
        "High" => "badge bg-danger",
        "Medium" => "badge bg-warning text-dark",
        "Low" => "badge bg-success",
        _ => "badge bg-secondary"
    };

    private RenderFragment RenderColumn(string columnName, List<TaskItem> tasks, string? leftStatus, string? rightStatus) => __builder =>
    {
        <div class="col-md-4">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>@columnName</strong>
                    <span class="badge bg-secondary">@tasks.Count</span>
                </div>
                <div class="card-body" style="min-height: 200px;">
                    @foreach (var task in tasks)
                    {
                        <div class="card mb-2">
                            <div class="card-body p-2">
                                <h6 class="card-title mb-1">@task.Title</h6>
                                <p class="card-text mb-1 small text-muted">@task.Assignee</p>
                                <div class="d-flex justify-content-between align-items-center mb-1">
                                    <span class="@GetPriorityClass(task.Priority)">@task.Priority</span>
                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                </div>
                                <div class="d-flex gap-1">
                                    @if (leftStatus is not null)
                                    {
                                        var left = leftStatus;
                                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTask(task, left)">← Move Left</button>
                                    }
                                    @if (rightStatus is not null)
                                    {
                                        var right = rightStatus;
                                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTask(task, right)">Move Right →</button>
                                    }
                                </div>
                            </div>
                        </div>
                    }

                    @if (_showForm[columnName])
                    {
                        <div class="card mb-2 border-primary">
                            <div class="card-body p-2">
                                <div class="mb-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Title"
                                           @bind="_formModels[columnName].Title" />
                                </div>
                                <div class="mb-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                           @bind="_formModels[columnName].Assignee" />
                                </div>
                                <div class="mb-2">
                                    <select class="form-select form-select-sm" @bind="_formModels[columnName].Priority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                </div>
                                <div class="mb-2">
                                    <input type="date" class="form-control form-control-sm"
                                           @bind="_formModels[columnName].DueDate" />
                                </div>
                                <div class="d-flex gap-1">
                                    <button class="btn btn-sm btn-primary" @onclick="() => SaveTask(columnName)">Save</button>
                                    <button class="btn btn-sm btn-secondary" @onclick="() => CancelForm(columnName)">Cancel</button>
                                </div>
                            </div>
                        </div>
                    }
                </div>
                <div class="card-footer">
                    <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => _showForm[columnName] = true">
                        + Add Task
                    </button>
                </div>
            </div>
        </div>
    };

    private class FormModel
    {
        public string Title { get; set; } = string.Empty;
        public string Assignee { get; set; } = string.Empty;
        public string Priority { get; set; } = "Medium";
        public DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    }
}

